options.systemMessage:
=Ты — классификатор намерений. Пользователь отвечает менеджеру по поводу условий работы (сдельная оплата, 20-60 мин, без переводов от пользователя).

Определи намерение пользователя и верни ТОЛЬКО JSON без markdown:
{
  "intent": "agree" | "doubt" | "decline",
  "doubt_topic": "краткая тема сомнения если intent=doubt, иначе пустая строка"
}

Сообщение пользователя: {{ $json.query }}

parameters.jsCode:
const raw = ($input.first().json.output || '').trim()
  .replace(/```json\n?/g,'').replace(/```/g,'');
let d;
try { d = JSON.parse(raw); } catch(e) { d = {intent:'doubt', doubt_topic:''}; }
return [{ json: { intent: d.intent || 'doubt', doubt_topic: d.doubt_topic || '' } }];

const ctx = $('Подготовка контекста').item.json;
const raw = ($input.first().json.output || '').trim()
  .replace(/```json\n?/g,'').replace(/```/g,'');
let d;
try { d = JSON.parse(raw); } catch(e) { d = {intent:'still_asking', selected_bank:''}; }

const LINKS = {
  VTB:   ctx.link_vtb_apply   || 'https://www.vtb.ru/',
  GPB:   ctx.link_gpb_apply   || 'https://www.gazprombank.ru/',
  OTP:   ctx.link_otp_apply   || 'https://www.otpbank.ru/',
  ALFA:  ctx.link_alfa_apply  || 'https://alfabank.ru/',
  TBANK: 'https://www.tbank.ru/'
};
const NAMES = {VTB:'ВТБ', GPB:'Газпромбанк', OTP:'ОТП', ALFA:'Альфа Банк', TBANK:'Т-Банк'};

return [{ json: {
  intent:        d.intent || 'still_asking',
  selected_bank: d.selected_bank || '',
  bank_link:     d.selected_bank ? (LINKS[d.selected_bank] || '') : '',
  bank_name:     d.selected_bank ? (NAMES[d.selected_bank] || '') : '',
} }];

const ctx = $('Подготовка контекста').item.json;
const LINKS = {
  VTB:'https://www.vtb.ru/', GPB:'https://www.gazprombank.ru/',
  OTP:'https://www.otpbank.ru/', ALFA:'https://alfabank.ru/', TBANK:'https://www.tbank.ru/'
};
const NAMES = {VTB:'ВТБ',GPB:'Газпромбанк',OTP:'ОТП',ALFA:'Альфа Банк',TBANK:'Т-Банк'};
const bank = ctx.task_bank || 'VTB';
const link = LINKS[bank] || LINKS.VTB;
const name = NAMES[bank] || bank;
return [{ json: {
  reply:      `Тогда выбираем ${name}. Ссылка для оформления заявки 👇\n${link}`,
  next_stage: 'WAIT_DELIVERY',
  admin_msg:  `[${ctx.cuid}] Ссылка на оформление отправлена (${bank}). Ждём дату доставки.`,
} }];

const ctx = $('Подготовка контекста').item.json;
const sum  = ctx.task_bank === 'VTB' ? '500' : '100';
return [{ json: {
  reply:      `Отлично! 🎉 Теперь нужно совершить одну покупку на сумму от ${sum}₽ (что угодно для себя).
После покупки пришли скриншот операции из приложения банка. Данные можно замазать — нужны сумма, дата и статус ✅`,
  next_stage: 'WAIT_PURCHASE_PROOF',
  admin_msg:  `[${ctx.cuid}] Карта получена (${ctx.task_bank}). Компенсация: ${sum}₽ на ${ctx.phone}.`,
  compensation_requested_to_admin: sum,
} }];

const ctx = $('Подготовка контекста').item.json;
const LINKS = {
  VTB:'https://www.vtb.ru/proverka', GPB:'https://www.gazprombank.ru/proverka',
  OTP:'https://www.otpbank.ru/proverka', ALFA:'https://alfabank.ru/proverka',
  TBANK:'https://www.tbank.ru/proverka'
};
const link = LINKS[ctx.task_bank] || LINKS.VTB;
return [{ json: {
  reply:      `Вижу, спасибо! 👍 Теперь последний шаг — заполни короткий отчёт о проверке:\n${link}\nЗаймёт 2–3 минуты 🙂`,
  next_stage: 'WAIT_REPORT_DONE',
  admin_msg:  `[${ctx.cuid}] Скриншот покупки получен (${ctx.task_bank}). Отправлена ссылка на отчёт.`,
  purchase_screenshot_received: 'yes',
  report_link_sent: 'yes',
} }];

const ctx = $('Подготовка контекста').item.json;
return [{ json: {
  reply:      'Отлично, спасибо! 🙌 Передаю на проверку. Как только подтвердят — переведём финальную выплату 500₽.
Когда придут деньги — напиши мне 🙂',
  next_stage: 'WAIT_REVIEW',
  admin_msg:  `[${ctx.cuid}] Отчёт заполнен (${ctx.task_bank}). Финальная выплата: 500₽ на ${ctx.phone}.`,
  report_done_user_confirm:        'yes',
  final_payout_requested_to_admin: '500',
} }];

options.systemMessage:
=Ты — классификатор намерений для этапа получения выплаты и отзыва.

История диалога: {{ $json.history_of_messages }}

Определи что написал пользователь и верни ТОЛЬКО JSON без markdown:
{
  "intent": "payout_confirmed" | "review_given" | "waiting"
}

- payout_confirmed: пользователь сообщает что деньги пришли (пришло, получил, перевод пришёл, +500 и т.п.)
- review_given: пользователь написал отзыв о проверке (если в истории уже был запрос отзыва)
- waiting: деньги ещё не пришли или вопрос о сроках

Сообщение пользователя: {{ $json.query }}

