  .replace(/```json\n?/g,'').replace(/```/g,'');
let d;
try { d = JSON.parse(raw); } catch(e) { d = {intent:'waiting'}; }
return [{ json: { intent: d.intent || 'waiting' } }];

const ctx = $('Подготовка контекста').item.json;
return [{ json: {
  reply:          'Супер! 🙌 Можешь написать короткий отзыв (1–2 предложения) — что выплатили и проверка была несложной? Прямо сюда в чат 🙏',
  next_stage:     'WAIT_REVIEW',
  admin_msg:      `[${ctx.cuid}] Выплата подтверждена (${ctx.task_bank}). Запросили отзыв.`,
  payout_confirmed: 'yes',
} }];

const ctx  = $('Подготовка контекста').item.json;
const user = $('Edit Fields').item.json.text || '';
return [{ json: {
  reply:         'Спасибо большое! 😊 У нас есть ещё одно задание — 2-й этап: проверка юридического сервиса Альфа банка. Нужно только оставить заявку, всё остальное объясню. Готов(а)?',
  next_stage:    'TASK2_OFFER',
  admin_msg:     `[${ctx.cuid}] Отзыв получен. Предложено задание 2.`,
  review_received: 'yes',
  review_text:   user,
} }];

